import ldap3

def search_user(username):
    server = ldap3.Server('ldap://myldapserver.com')
    conn = ldap3.Connection(server, user='uid=admin,dc=example,dc=com', password='password')
    
    if not conn.bind():
        print('error in bind: ', conn.result)
        
    search_base = 'dc=example,dc=com'
    search_filter = f'(uid={username})'
    attributes = ['cn']
    
    conn.search(search_base=search_base, 
                search_filter=search_filter, 
                attributes=attributes)

    return [i['dn'] for i in conn.entries] if conn.entries else None